import React, { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import './AuthPage.css';

function LoginPage() {
  const navigate = useNavigate();
  const auth = useAuth?.() || {};
  const login = auth?.login || (async () => true);

  const [form, setForm] = useState({
    email: '',
    password: '',
    rememberMe: true,
  });

  const [focusedField, setFocusedField] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState('');

  const emailValid = useMemo(() => {
    return /\S+@\S+\.\S+/.test(form.email);
  }, [form.email]);

  const passwordValid = useMemo(() => {
    return form.password.trim().length >= 6;
  }, [form.password]);

  const canSubmit = emailValid && passwordValid && !isSubmitting;

  const handleChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!canSubmit) return;

    setIsSubmitting(true);
    setError('');

    try {
      const result = await login({
        email: form.email,
        password: form.password,
        rememberMe: form.rememberMe,
      });

      if (result === false) {
        throw new Error('로그인에 실패했습니다.');
      }

      navigate('/dashboard');
    } catch (err) {
      setError(err?.message || '로그인 중 오류가 발생했습니다. 다시 시도해주세요.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <section className="auth-page auth-login-page">
      <div className="auth-aurora auth-aurora-1"></div>
      <div className="auth-aurora auth-aurora-2"></div>
      <div className="auth-aurora auth-aurora-3"></div>

      <div className="container auth-layout">
        <div className="auth-brand-panel">
          <Link to="/" className="auth-brand-link">
            <div className="auth-brand-mark">
              <span className="auth-brand-ring"></span>
              <span className="auth-brand-dot"></span>
            </div>

            <div className="auth-brand-copy">
              <strong>메이티</strong>
              <span>AI Emotion Companion</span>
            </div>
          </Link>

          <div className="auth-brand-content">
            <div className="auth-page-badge">Welcome back</div>

            <h1 className="auth-brand-title">
              다시 만나는 순간도
              <br />
              <span className="gradient-text">부드럽고 신뢰감 있게</span>
            </h1>

            <p className="auth-brand-description">
              메이티는 단순한 로그인 화면도 하나의 제품 경험으로 설계합니다.
              익숙함은 유지하고, 감성은 더 섬세하게, 인터랙션은 더 매끄럽게 구성했습니다.
            </p>

            <div className="auth-feature-list">
              <div className="auth-feature-item">
                <span className="auth-feature-dot"></span>
                <div>
                  <strong>끊김 없는 대화 이어가기</strong>
                  <p>웹과 데스크톱에서 같은 흐름으로 바로 연결됩니다.</p>
                </div>
              </div>

              <div className="auth-feature-item">
                <span className="auth-feature-dot"></span>
                <div>
                  <strong>개인화된 캐릭터 경험 유지</strong>
                  <p>설정된 성향과 대화 톤이 그대로 이어집니다.</p>
                </div>
              </div>

              <div className="auth-feature-item">
                <span className="auth-feature-dot"></span>
                <div>
                  <strong>보안 중심 인증 흐름</strong>
                  <p>민감한 감정 대화에 맞는 신뢰 중심 접근을 지향합니다.</p>
                </div>
              </div>
            </div>

            <div className="auth-floating-metrics">
              <div className="auth-metric-card">
                <span className="auth-metric-label">Mood Safe</span>
                <strong>Private</strong>
              </div>
              <div className="auth-metric-card">
                <span className="auth-metric-label">Experience</span>
                <strong>Seamless</strong>
              </div>
            </div>
          </div>
        </div>

        <div className="auth-form-panel">
          <div className="auth-form-shell glow-ring">
            <div className="auth-form-header">
              <div>
                <span className="auth-form-eyebrow">Sign In</span>
                <h2>로그인</h2>
                <p>메이티 계정으로 감정 대화를 이어가세요.</p>
              </div>

              <div className="auth-form-status">
                <span className="auth-status-dot"></span>
                Secure Access
              </div>
            </div>

            <form className="auth-form" onSubmit={handleSubmit}>
              <div
                className={`auth-input-group ${
                  focusedField === 'email' ? 'focused' : ''
                } ${form.email ? 'filled' : ''}`}
              >
                <label htmlFor="login-email">이메일</label>
                <input
                  id="login-email"
                  type="email"
                  placeholder="name@example.com"
                  value={form.email}
                  onFocus={() => setFocusedField('email')}
                  onBlur={() => setFocusedField('')}
                  onChange={(e) => handleChange('email', e.target.value)}
                  autoComplete="email"
                />
                <span className={`auth-valid-chip ${emailValid ? 'valid' : ''}`}>
                  {form.email ? (emailValid ? '유효한 이메일' : '이메일 형식 확인') : '입력 대기'}
                </span>
              </div>

              <div
                className={`auth-input-group ${
                  focusedField === 'password' ? 'focused' : ''
                } ${form.password ? 'filled' : ''}`}
              >
                <label htmlFor="login-password">비밀번호</label>
                <div className="auth-password-wrap">
                  <input
                    id="login-password"
                    type={showPassword ? 'text' : 'password'}
                    placeholder="비밀번호를 입력하세요"
                    value={form.password}
                    onFocus={() => setFocusedField('password')}
                    onBlur={() => setFocusedField('')}
                    onChange={(e) => handleChange('password', e.target.value)}
                    autoComplete="current-password"
                  />
                  <button
                    type="button"
                    className="auth-toggle-btn"
                    onClick={() => setShowPassword((prev) => !prev)}
                  >
                    {showPassword ? '숨김' : '보기'}
                  </button>
                </div>
                <span className={`auth-valid-chip ${passwordValid ? 'valid' : ''}`}>
                  {form.password ? (passwordValid ? '사용 가능' : '6자 이상 입력') : '입력 대기'}
                </span>
              </div>

              <div className="auth-row between">
                <label className="auth-check">
                  <input
                    type="checkbox"
                    checked={form.rememberMe}
                    onChange={(e) => handleChange('rememberMe', e.target.checked)}
                  />
                  <span>로그인 상태 유지</span>
                </label>

                <button type="button" className="auth-text-btn">
                  비밀번호 찾기
                </button>
              </div>

              {error && <div className="auth-error-box">{error}</div>}

              <button
                type="submit"
                className={`btn btn-primary auth-submit-btn ${
                  isSubmitting ? 'loading' : ''
                }`}
                disabled={!canSubmit}
              >
                {isSubmitting ? (
                  <>
                    <span className="auth-spinner"></span>
                    로그인 중...
                  </>
                ) : (
                  '로그인'
                )}
              </button>

              <div className="auth-divider">
                <span>또는</span>
              </div>

              <div className="auth-social-grid">
                <button type="button" className="auth-social-btn">
                  <span>G</span>
                  Google로 계속하기
                </button>
                <button type="button" className="auth-social-btn">
                  <span></span>
                  Apple로 계속하기
                </button>
              </div>

              <div className="auth-bottom-copy">
                아직 계정이 없으신가요? <Link to="/signup">회원가입</Link>
              </div>
            </form>

            <div className="auth-floating-pill top">Private by Design</div>
            <div className="auth-floating-pill bottom">Emotion-first UX</div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default LoginPage;
